SELECT * FROM device_info



            AND device_no = #{device.deviceNo}


            AND device_name LIKE CONCAT('%', #{device.deviceName}, '%')


            AND category_id = #{device.categoryId}


            AND status = #{device.status}


            AND laboratory LIKE CONCAT('%', #{device.laboratory}, '%')


    AND deleted = 0

ORDER BY create_time DESC
